TIM_BDTRInitTypeDef是定时器BDTR的初始化结构体类型。在初始化定时器BDTR寄存器时，需要先定义并初始化一个TIM_BDTRInitStructure结构体变量，并对该结构体变量的成员进行赋值，最后使用TIM_BDTRConfig函数将赋值后的结构体变量作为参数，配置定时器BDTR寄存器。

TIM_BDTRInitStructure结构体中包含以下成员：
- TIM_OSSRState：开启死区控制输出同步，取值为ENABLE或DISABLE。
- TIM_OSSIState：开启死区控制输出异步，取值为ENABLE或DISABLE。
- TIM_LOCKLevel：锁定定时器的级别，取值为TIM_LOCKLevel_OFF、TIM_LOCKLevel_1、TIM_LOCKLevel_2或TIM_LOCKLevel_3。
- TIM_DeadTime：死区时间，取值范围为0~255。
- TIM_Break：定时器故障使能，取值为TIM_Break_Enable或TIM_Break_Disable。
- TIM_BreakPolarity：定时器故障极性，取值为TIM_BreakPolarity_Low或TIM_BreakPolarity_High。
- TIM_AutomaticOutput：切换定时器自动输出使能，取值为ENABLE或DISABLE。

例如，初始化TIM_BDTRInitStructure结构体可以这样实现：

```
TIM_BDTRInitTypeDef TIM_BDTRInitStruct;
TIM_BDTRInitStruct.TIM_OSSRState = TIM_OSSRState_Enable;
TIM_BDTRInitStruct.TIM_OSSIState = TIM_OSSIState_Enable;
TIM_BDTRInitStruct.TIM_LOCKLevel = TIM_LOCKLevel_OFF;
TIM_BDTRInitStruct.TIM_DeadTime = 50;
TIM_BDTRInitStruct.TIM_Break = TIM_Break_Disable;
TIM_BDTRInitStruct.TIM_BreakPolarity = TIM_BreakPolarity_Low;
TIM_BDTRInitStruct.TIM_AutomaticOutput = ENABLE;
TIM_BDTRConfig(TIM1, &TIM_BDTRInitStruct);
```

好的，下面是一个使用TIM1定时器生成50Hz PWM以及给出占空比调整接口的例子：

```
#include "stm32f10x.h"

void TIM1_PWM_Init(uint16_t arr, uint16_t psc);
void TIM1_PWM_SetDutyCycle(uint16_t dutyCycle);

int main(void)
{
    TIM1_PWM_Init(20000 - 1, 72 - 1);

    while(1)
    {
        // 调整占空比为20%
        TIM1_PWM_SetDutyCycle(4000);
        // 延时1秒
        for(uint32_t i = 0; i < 7200000; i++) ;
        // 调整占空比为80%
        TIM1_PWM_SetDutyCycle(16000);
        // 延时1秒
        for(uint32_t i = 0; i < 7200000; i++) ;
    }
}

/**
  * @brief  TIM1_PWM_Init
  * @param  arr: 设置自动重装载值
  * @param  psc: 设置预分频值
  * @retval None
  */
void TIM1_PWM_Init(uint16_t arr, uint16_t psc)
{
    GPIO_InitTypeDef GPIO_InitStructure;
    TIM_TimeBaseInitTypeDef TIM_TimeBaseStructure;
    TIM_OCInitTypeDef TIM_OCInitStructure;

    // 使能TIM1、GPIOA时钟
    RCC_APB2PeriphClockCmd(RCC_APB2Periph_TIM1 | RCC_APB2Periph_GPIOA, ENABLE);

    // 设置GPIOA的PA8引脚为复用推挽模式
    GPIO_InitStructure.GPIO_Pin = GPIO_Pin_8;
    GPIO_InitStructure.GPIO_Mode = GPIO_Mode_AF_PP;
    GPIO_InitStructure.GPIO_Speed = GPIO_Speed_50MHz;
    GPIO_Init(GPIOA, &GPIO_InitStructure);

    // 设置TIM1的定时器分频系数、计数模式等
    TIM_TimeBaseStructure.TIM_Prescaler = psc;
    TIM_TimeBaseStructure.TIM_CounterMode = TIM_CounterMode_Up;
    TIM_TimeBaseStructure.TIM_Period = arr;
    TIM_TimeBaseStructure.TIM_ClockDivision = 0;
    TIM_TimeBaseInit(TIM1, &TIM_TimeBaseStructure);

    // 初始化TIM1的PWM模式
    TIM_OCInitStructure.TIM_OCMode = TIM_OCMode_PWM1;
    TIM_OCInitStructure.TIM_OutputState = TIM_OutputState_Enable;
    TIM_OCInitStructure.TIM_Pulse = 0;
    TIM_OCInitStructure.TIM_OCPolarity = TIM_OCPolarity_High;
    TIM_OC1Init(TIM1, &TIM_OCInitStructure);

    // 使能TIM1输出比较通道1
    TIM_CtrlPWMOutputs(TIM1, ENABLE);
    // 启动TIM1定时器
    TIM_Cmd(TIM1, ENABLE);
}

/**
  * @brief  TIM1_PWM_SetDutyCycle
  * @param  dutyCycle: 期望的占空比，范围为0~19999
  * @retval None
  */
void TIM1_PWM_SetDutyCycle(uint16_t dutyCycle)
{
    TIM_SetCompare1(TIM1, dutyCycle);
}
```

上面的代码中，TIM1_PWM_Init函数用于初始化TIM1定时器，并将其设置为PWM模式。TIM1_PWM_SetDutyCycle函数用于设置PWM信号的占空比。通过调用TIM1_PWM_SetDutyCycle函数，并传入期望的占空比值，可以改变PWM信号的占空比，从而实现控制舵机等作用。

在main函数中，为了展示占空比调整的效果，使用了循环来轮流调整占空比，以观察PWM波形的变化。
